// One link in a pop chain : the item/KI you need, and the mob/NPC it drops from.
// childFirst/childCount = the pops needed to force-spawn THAT mob (0 = it is a natural/timed spawn).
struct NmPop {
    unsigned short id;          // key-item id when isKI, else item id
    unsigned char  isKI;        // 1 = key item (Lua type == 'key item') ; 0 = item
    const char*    fromName;    // free text : mob/NPC + map position
    unsigned short childFirst;  // index into POPS[]
    unsigned short childCount;
};

struct Nm {
    const char*    key;         // lowercase lookup key ("briareus", "arch dynamis lord")
    const char*    en;          // display name ("Briareus")
    unsigned short collectable; // item id of the collectable, or 0 if the NM has none
    unsigned short collectableTarget; // target count, or 0
    unsigned short popFirst;    // index into POPS[]
    unsigned short popCount;
};

