// Case-sensitive lookup by lowercase key ("briareus"), or 0 if unknown.
inline const Nm* nm_by_key(const char* key) {
    if (!key) return 0;
    int lo = 0, hi = NMS_N - 1;
    while (lo <= hi) { const int mid = (lo + hi) >> 1;
        const char* a = NMS[mid].key; const char* b = key;
        while (*a && *a == *b) { ++a; ++b; }
        const int c = (int)(unsigned char)*a - (int)(unsigned char)*b;
        if (c == 0) return &NMS[mid]; if (c < 0) lo = mid + 1; else hi = mid - 1; }
    return 0;
}

